def set_text(paragraph, text):
    paragraph.text = ""
    run = paragraph.add_run(text)
    run.font.name = "宋体"
    run._element.rPr.rFonts.set(qn("w:eastAsia"), "宋体")


def main():
    shutil.copy2(SRC, OUT)
    doc = Document(OUT)
    changed = 0
    for paragraph in doc.paragraphs:
        text = paragraph.text.strip()
        if text in REPLACEMENTS:
            set_text(paragraph, REPLACEMENTS[text])
            changed += 1
    doc.save(OUT)

    checked = Document(OUT)
    all_text = "\n".join(p.text for p in checked.paragraphs)
    print(f"saved={OUT}")
    print(f"changed={changed}")
    print(f"paragraphs={sum(1 for p in checked.paragraphs if p.text.strip())}")
    print(f"chars={sum(len(p.text.strip()) for p in checked.paragraphs if p.text.strip())}")
    for term in ["系统能够", "本文系统", "该页面", "测试结果表明"]:
        print(f"{term}={all_text.count(term)}")


if __name__ == "__main__":
    main()
